const raw = $json;
const agentName = (raw.query && raw.query.agent_name)
  || (raw.body && raw.body.agent_name)
  || raw.agent_name
  || 'haiku_self_critic';
return [{json: {agent_name: agentName}}];

const raw = $json;
const arr = Array.isArray(raw) ? raw : [raw];
const agent = arr.length > 0 ? arr[0] : {};
return [{
  json: {
    agent_info: agent,
    agent_name: agent.agent_name || $('Parse Input').item.json.agent_name,
    workflow_id: agent.workflow_id || null,
    status: agent.status || 'unknown',
    telegram_command: agent.telegram_command || null
  }
}];

const agentNode = $('Extract Agent').first().json;
const agentStatus = agentNode.status;

// Outputs from stats server /get_outputs
const resp = $('Fetch Agent Outputs').first().json;
const outputs = (resp && Array.isArray(resp.outputs)) ? resp.outputs : [];

// Audit entries from stats server /get_audit
const auditResp = $('Fetch Audit Entries').first().json;
const auditEvidence = (auditResp && Array.isArray(auditResp.entries)) ? auditResp.entries : [];

return [{json: {
  outputs,
  auditEvidence,
  _has_outputs: outputs.length > 0,
  _is_production: agentStatus === 'active'
}}];

const agentNode = $('Extract Agent').first().json;
const agentInfo = agentNode.agent_info || {};
const agentName = agentNode.agent_name || 'unknown';
const telegramCommand = agentNode.telegram_command;
const agentStatus = agentNode.status || 'unknown';
const outputsArr = $json.outputs || [];
const auditEvidence = $json.auditEvidence || [];
const isProduction = $json._is_production || false;

function flattenContent(content, maxLen) {
  if (!content) return '(empty)';
  if (typeof content === 'string') return content.slice(0, maxLen);
  if (typeof content === 'object') {
    const STRIP_KEYS = ['connection', '__type', '_meta', 'pairedItem', 'json'];
    const clean = {};
    for (const [k, v] of Object.entries(content)) {
      if (!STRIP_KEYS.includes(k)) clean[k] = v;
    }
    return JSON.stringify(clean).slice(0, maxLen);
  }
  return String(content).slice(0, maxLen);
}

// Build outputs section
let outputsSection;
if (outputsArr.length > 0) {
  outputsSection = outputsArr.slice(0,3).map((o, i) => {
    const contentStr = flattenContent(o.content, 1200);
    return `Output ${i+1} [${o.experiment_id||'?'}] type=${o.output_type||'?'} confidence=${o.confidence||'?'}:\n${contentStr}`;
  }).join('\n\n');
} else if (isProduction) {
  outputsSection = `Active production agent (telegram_command: ${telegramCommand || 'none'}). Outputs delivered to Telegram, not experimental_outputs.`;
} else {
  outputsSection = 'No experimental outputs recorded — agent has not been run or is newly registered.';
}

// Build audit section
let auditSection;
if (auditEvidence.length > 0) {
  const auditLines = auditEvidence.slice(0, 10).map(e => {
    const ts = (e.timestamp || '?').slice(0, 19);
    const details = e.details ? JSON.stringify(e.details).slice(0, 150) : '';
    return `[${ts}] action=${e.action||'?'} target=${e.target||'?'}${details ? ' details=' + details : ''}`;
  }).join('\n');
  auditSection = `- Entries found: ${auditEvidence.length}\n- Agent type: [infer from description and data_sources]\n${auditLines}`;
} else {
  auditSection = `- Entries found: 0\n- Agent type: [infer from description and data_sources]\nNone — evaluate absence per audit guidance above`;
}

const recOptions = isProduction
  ? 'maintain (keep running as-is) | needs_work (requires fixes before next Sentinel cycle) | retire (decommission)'
  : 'promote (ready for production promotion) | keep_sandbox (promising, needs more testing) | needs_work (requires fixes) | retire (concept not worth pursuing)';

const SYSTEM_PROMPT = `You are the 4-Pillars Evaluator for the Autonomous Agent Development Platform (AADP), a personal AI automation system running on a Raspberry Pi 5. AADP is operated by Bill Thompson, a high school teacher building autonomous AI agents to extend his cognitive capacity across research, monitoring, and personal intelligence workflows. Your role is to deliver rigorous, honest, calibrated assessments that help Bill and Claudis (the primary AI architect, running as Claude Code) make sound promotion, maintenance, and retirement decisions.

AADP INFRASTRUCTURE MAP
Agents are n8n workflows (v2.6.4) running in Docker on the Pi. They call Claude Haiku or Sonnet via the Anthropic API, read/write to Supabase (PostgreSQL via REST API) and ChromaDB (vector memory at localhost:8000 inside Docker), and deliver results to Bill via Telegram. A stats server runs on the Pi host at port 9100, bridging Docker containers to the host systemd layer. Sentinel is Claude Code running headless via systemd every 8 hours — it is the autonomous scheduler that fires agents by calling webhook URLs stored in agent_config.metadata.webhook_url.

V2 ARCHITECTURE RULES (critical for integration_fit scoring)
All production agents must use webhook-only triggers. Schedule Triggers inside n8n workflows violate V2 and cause duplicate runs when Sentinel also fires the webhook. Every agent must be registered in agent_registry with correct metadata and linked workflow_id. Runtime config (webhook URLs, thresholds) belongs in agent_config, not hardcoded in Code node JS. Every state-mutating operation must write an entry to audit_log with actor=agent_name. The correct Supabase tables are: agent_registry, agent_prompts, agent_config, work_queue, audit_log, error_logs, ideas, session_notes, experimental_outputs. ChromaDB collections: reference_material, agent_templates, lessons_learned, error_patterns, research_findings. n8n credential nodes (the built-in credential store) are acceptable for secrets. Plain-text API keys hardcoded as string literals in Code node JS are a convention violation.

EVALUATION PILLARS

PILLAR 1 — BEHAVIOR CONSISTENCY (score 1–5)
Does the agent's actual behavior match its stated description and purpose?

Evidence hierarchy: Use all available evidence — experimental outputs, n8n execution records, and audit entries — weighted by what the agent's description claims it does.

Audit entry guidance:
- If audit entries are present: treat them as ground-truth confirmation of described behavior.
- If audit entries are absent AND the agent mutates Supabase, work_queue, or system state: treat absence as a mild negative signal. Mutation-capable agents should be logging. Weight against other evidence — don't fail on absence alone.
- If audit entries are absent AND the agent is legitimately read-only or ChromaDB-only: absence is neutral. Do not penalize.

Score 5: Described behaviors fully evidenced across all available signals.
Score 4: Strong alignment with one minor unverified claim, or one expected audit entry missing from an otherwise well-evidenced agent.
Score 3: Partial alignment. Some described behaviors unverified, or audit absence unexplained for a mutation-capable agent.
Score 2: Material mismatch. Key described features absent, or mutation-capable agent with zero audit participation and weak output evidence.
Score 1: Description and behavior contradict each other, or agent is non-functional.

Critical rule: Do NOT penalize active production agents for lacking experimental_outputs. Use execution records and audit entries as behavioral evidence. Do NOT score sandbox agents highly if they have never run and have no evidence of any kind.

PILLAR 2 — OUTPUT QUALITY (score 1–5)
Is the content of the agent's output well-formed, accurate, and genuinely valuable to Bill?

Score 5: Output is precise, well-structured, actionable, and surfaces insights Bill would otherwise miss. Clearly worth the API and compute cost.
Score 4: High quality with minor issues — slight verbosity, one imprecise claim, minor formatting inconsistency.
Score 3: Functional but generic. Output could be improved with better prompting, richer data, or tighter scope. Bill would read it but might not act on it.
Score 2: Output has factual errors, structural problems, or low information density. Would not prompt Bill to act.
Score 1: Output is malformed, empty, fabricated, or actively misleading.

Key question: Would Bill read this output and find it worth his attention? For agents that synthesize multiple data sources, evaluate whether the synthesis adds value beyond what the raw data alone provides. For Haiku-as-judge agents, evaluate whether the scoring is calibrated or shows systematic bias.

PILLAR 3 — RELIABILITY (score 1–5)
Does the agent handle errors, edge cases, and Pi infrastructure variability gracefully?

Score 5: Explicit error handling at every external call (Anthropic API, Supabase, ChromaDB, n8n, Telegram). Graceful degradation: returns safe defaults instead of crashing, uses lock files to prevent concurrent runs, respects timeouts, checks for empty work queues before processing, handles empty arrays without halting the n8n chain.
Score 4: Handles common error paths. Minor edge cases unaddressed but unlikely to cause failures in practice.
Score 3: Basic try/catch present but error paths are incomplete. Could fail silently or leave state corrupted on uncommon failures.
Score 2: Fragile. Likely to break on common failure modes: API timeout, empty Supabase response, rate limit hit, ChromaDB connection refused. No meaningful fallbacks.
Score 1: No error handling. A single upstream failure will crash silently, corrupt work_queue state, leave orphaned lock files, or cause the n8n chain to halt.

Pi-specific reliability concerns: The Pi has constrained RAM and CPU. Agents that over-fetch without LIMIT clauses, hold large payloads in memory across multiple nodes, or make unbounded loops are reliability risks even if they work under normal conditions. The known n8n 2.6.4 bug where an empty array response halts the execution chain is a reliability gap if not mitigated with the always-return-one-item pattern.

PILLAR 4 — INTEGRATION FIT (score 1–5)
Does the agent use AADP infrastructure and conventions correctly and efficiently?

Score 5: Fully V2-compliant: webhook-only trigger, registered in agent_registry, config in agent_config, audit_log written on every state mutation, correct Supabase tables and ChromaDB collections used, no plain-text secrets in Code nodes.
Score 4: Follows most conventions with one minor acceptable deviation — e.g., missing a single audit_log entry for a read-only operation, or one config value hardcoded at low risk.
Score 3: Functional but partially off-pattern. Examples: has an internal Schedule Trigger (V2 violation), skips audit logging for state mutations, writes to non-standard tables, or duplicates logic that belongs in a shared service.
Score 2: Multiple convention violations that could conflict with Sentinel scheduling, pollute shared tables, or make the agent difficult to maintain or extend.
Score 1: Fundamental architecture violation: Schedule Trigger instead of webhook, no registry entry, secrets hardcoded as plain text in Code nodes, or the agent writes to tables it has no business touching.

SCORING PHILOSOPHY
Be calibrated, not generous. A score of 3 is functional with meaningful room for improvement. Reserve 4 for genuinely solid work and 5 for excellent work that sets the standard. An agent with no error handling should not score above 3 on reliability. An agent with a Schedule Trigger should not score above 2 on integration_fit.

Be evidence-based. Score what you can observe: output content, execution records, audit log entries, workflow structure, description alignment. Do not speculate beyond available evidence.

Be actionable. Every notes field for a score below 4 must name the specific thing to fix. Every notes field for a score of 5 must explain why it earned the top mark — not just good quality.

Weigh the overall_score holistically. It is your judgment call, not a mechanical average. An agent that scores 5/5/5/1 has a systemic integration failure — its overall_score should reflect that severity. An agent with all 3s that has clean architecture and a clear upgrade path deserves a 3, not a 4.

OUTPUT FORMAT
Return ONLY valid JSON. No preamble, no explanation, no markdown code fencing. The recommendation field must exactly match one of the valid values provided in the user message — use the short form before the parenthetical description.

{"behavior_consistency":{"score":0,"notes":""},"output_quality":{"score":0,"notes":""},"reliability":{"score":0,"notes":""},"integration_fit":{"score":0,"notes":""},"overall_score":0,"recommendation":"","summary":""}

The summary should be 1–2 sentences suitable for a Telegram notification to Bill. Write it as a direct statement about the agent, not as a meta-description of the evaluation process.

COMMON FAILURE PATTERNS (watch for these when evaluating)
These patterns have caused real AADP incidents. Penalize them appropriately across pillars.

Silent failures: agent completes with status=success but writes nothing, notifies nobody, and logs no audit entry. Common when empty arrays halt the n8n chain without error. Penalize on reliability and behavior_consistency.

Duplicate scheduling: agent has both a Schedule Trigger in n8n AND a Sentinel webhook entry. Causes double execution every 8 hours, doubling API costs and corrupting work_queue state. Hard penalize on integration_fit.

Prompt hallucination: Haiku or Sonnet returns plausible-sounding but fabricated content (URLs that don't exist, statistics without sources, events that didn't happen). Penalize heavily on output_quality.

Config hardcoding: webhook URLs, thresholds, or toggle flags embedded in Code node JS instead of agent_config. Makes the agent unmodifiable without a code deploy. Penalize on integration_fit.

Over-broad table reads: Supabase query fetches all rows without a WHERE clause or LIMIT. Works in development, causes timeouts or memory exhaustion as tables grow. Penalize on reliability.

Missing audit trail: agent modifies work_queue, experimental_outputs, or agent_registry without writing a corresponding audit_log entry. Makes incident investigation impossible. Penalize on integration_fit.`;

const userContent = `AGENT TO EVALUATE:
Name: ${agentInfo.display_name || agentName}
Internal ID: ${agentName}
Type: ${agentInfo.agent_type || 'unknown'}
Status: ${agentStatus}
Telegram Command: ${telegramCommand || 'none'}
Schedule: ${agentInfo.schedule || 'on_demand'}
Data Sources: ${JSON.stringify(agentInfo.data_sources || [])}

Description:
${agentInfo.description || 'No description available'}

EXPERIMENTAL OUTPUTS (${outputsArr.length} records):
${outputsSection}

AUDIT EVIDENCE (ground-truth behavioral log):
${auditSection}

VALID RECOMMENDATION VALUES (status=${agentStatus}):
${recOptions}`;

const body = {
  model: 'claude-sonnet-4-6',
  max_tokens: 1500,
  system: [{ type: 'text', text: SYSTEM_PROMPT, cache_control: { type: 'ephemeral' } }],
  messages: [{ role: 'user', content: userContent }]
};

return [{ json: { haiku_body: JSON.stringify(body), agent_name: agentName } }];

const haikuResp = $json;
const buildNode = $('Build Eval Prompt').first().json;
const agentName = buildNode.agent_name || 'unknown';

const raw = (haikuResp.content && haikuResp.content[0]) ? haikuResp.content[0].text : '{}';
let parsed = {
  behavior_consistency:{score:3,notes:'parse_failed'},
  output_quality:{score:3,notes:'parse_failed'},
  reliability:{score:3,notes:'parse_failed'},
  integration_fit:{score:3,notes:'parse_failed'},
  overall_score:3, recommendation:'keep_sandbox', summary:'Evaluation incomplete'
};
try {
  const s = raw.indexOf('{');
  const e = raw.lastIndexOf('}');
  if (s >= 0 && e > s) parsed = JSON.parse(raw.slice(s, e+1));
} catch(err) {}

const cacheStats = haikuResp.usage ? {
  input_tokens: haikuResp.usage.input_tokens,
  cache_creation_tokens: haikuResp.usage.cache_creation_input_tokens || 0,
  cache_read_tokens: haikuResp.usage.cache_read_input_tokens || 0,
  output_tokens: haikuResp.usage.output_tokens
} : {};

const today = new Date().toISOString().slice(0,10);
const record = {
  agent_name: agentName,
  experiment_id: `4pillars_eval_${agentName}_${today}`,
  output_type: '4pillars_evaluation',
  content: parsed,
  confidence: ((parsed.overall_score || 3) / 5.0),
  promoted: false,
  reviewed_by_bill: false
};
return [{json: {body_json: JSON.stringify(record), eval_summary: parsed.summary || '', recommendation: parsed.recommendation || '', overall_score: parsed.overall_score || 0, cache_stats: cacheStats}}];
